import streamlit as stfrom src.main import run_queryst.set_page_config(page_title="I-MED Procedure Q&A", page_icon="🩻")st.title("I-MED Procedure Q&A")st.write(    "Ask a question about I-MED imaging procedures. "    "Answers are grounded in scraped procedure pages.")query = st.text_input(    "Enter your question",    placeholder="e.g. How do I prepare for an abdominal ultrasound?")if st.button("Ask"):    if not query.strip():        st.warning("Please enter a question.")    else:        try:            response = run_query(query)            st.subheader("Answer")            st.write(response["answer"])            if response["sources"]:                st.subheader("Sources")                for s in response["sources"]:                    st.write(s)            if response.get("used_chunk_details"):                with st.expander("Retrieved chunks"):                    for chunk in response["used_chunk_details"]:                        st.write("Chunk ID:", chunk["chunk_id"])                        st.write("Similarity score:", chunk["score"])                        st.write("Rerank score:", chunk["rerank_score"])                        st.write(chunk["text"])                        st.write("---")        except Exception as e:            st.error(str(e))